/**
 * Service for checking content exclusion rules.
 *
 * This service fetches exclusion rules from the GitHub API and caches them.
 * It provides methods to check if files should be excluded based on:
 * - Path patterns (glob matching)
 * - Content patterns (regex matching via ifAnyMatch/ifNoneMatch)
 *
 * Usage:
 * 1. Create an instance with auth info
 * 2. Call startFetching() at session start (non-blocking)
 * 3. Call isExcluded() when checking files (blocks until fetch complete if needed)
 *
 * The fetch orchestration, rule cache, and path/content evaluation run in the
 * native runtime; this class owns the JS-side lifecycle (handle refcount and
 * finalizer), forwards telemetry, and replays the logs the runtime returns.
 */
declare class ContentExclusionService {
    private readonly featureEnabled;
    private disposed;
    private retainCount;
    private readonly finalizerToken;
    /** Handle to the native content exclusion service instance. */
    private readonly runtimeHandle;
    /** Optional callback for emitting telemetry events */
    private readonly onTelemetry?;
    constructor(host: string, token: string | undefined, featureEnabled: boolean, onTelemetry?: (event: TelemetryEvent) => void, additionalPolicies?: ContentExclusionApiResponse[]);
    retain(): void;
    dispose(): void;
    isUnavailable(): boolean;
    private getUnavailableResult;
    /**
     * Starts fetching exclusion rules for repositories in the given directories.
     * This method is non-blocking - it kicks off the fetch but doesn't wait.
     *
     * @param directories Directories to scan for git repositories
     */
    startFetching(directories: string[]): void;
    /**
     * Runs the native fetch, replays the returned logs, and forwards telemetry.
     */
    private runFetch;
    /**
     * Returns whether any content exclusion rules are active.
     * Awaits the initial fetch if still in progress.
     */
    hasRules(): Promise<boolean>;
    /**
     * Checks if a file is excluded by content exclusion rules.
     *
     * This method will block on the initial fetch if it hasn't completed yet.
     *
     * @param absolutePath Absolute path to the file
     * @returns Exclusion check result with excluded status and reason
     */
    isExcluded(absolutePath: string): Promise<ExclusionCheckResult>;
    /**
     * Checks if any files in a list are excluded.
     * Useful for shell command checking via possiblePaths.
     *
     * @param absolutePaths Array of absolute file paths
     * @param options.onlyExisting When true, paths that do not exist on disk are
     *   ignored before checking exclusion. Shell `possiblePaths` is an
     *   over-approximation that can include phantom paths (command names,
     *   subcommands, and other bare words resolved under the cwd) that never
     *   exist on disk. A path that does not exist cannot reference protected
     *   content, so callers checking shell commands set this to avoid
     *   false-positive blocks on those phantom paths. Explicit read/write
     *   targets (view/edit/create) must leave this unset so that not-yet-created
     *   files remain protected.
     * @param options.cwd The working directory the paths were resolved against.
     *   Used only to recover the original (pre-resolution) token for the
     *   glob-metacharacter heuristic in {@link filterExistingPaths}; see that
     *   method for why the token, not the absolute path, must be inspected.
     * @returns First excluded path and its result, or null if none excluded
     */
    findFirstExcluded(absolutePaths: string[], options?: {
        onlyExisting?: boolean;
        cwd?: string;
    }): Promise<{
        path: string;
        result: ExclusionCheckResult;
    } | null>;
    /**
     * Filters a list of paths down to those that could reference real content on
     * disk, i.e. paths that currently exist.
     *
     * Paths containing shell glob/wildcard metacharacters (`*`, `?`, `[`, `]`,
     * `{`, `}`) are kept regardless of existence: the shell expands them at
     * runtime, so they never `stat()` as a literal file, but they can still
     * resolve to excluded content (e.g. `cat *.secret` reading `passwords.secret`).
     * Dropping them would let a glob bypass an exclusion rule it matches, so we
     * conservatively keep them and let pattern matching decide. Command-name
     * phantoms (`git`, `Get-Location`) never contain these characters, so this
     * does not reintroduce the over-blocking this filter is meant to prevent.
     *
     * The metacharacter test runs against the original (pre-resolution) token,
     * recovered via `cwd`, rather than the resolved absolute path. A working
     * directory that itself contains `[`, `]`, `{`, or `}` (e.g. `/repo/cache[1]`)
     * would otherwise make every relative phantom candidate resolved under it look
     * like a glob, short-circuit the existence check, and re-introduce the
     * over-blocking this filter prevents.
     */
    private filterExistingPaths;
    /**
     * Gets the formatted error message for an excluded file.
     */
    getExclusionMessage(filePath: string): string;
    /**
     * Returns the native service handle so a streaming line filter can drive
     * exclusion checks directly, or `undefined` once the service is disposed so
     * the filter observes the service as unavailable.
     */
    getRuntimeHandleForFilter(): number | undefined;
    /**
     * Returns whether content exclusion is enabled for this service. Readable
     * even after disposal (the flag is fixed at construction), so the streaming
     * line filter can pair it with `getRuntimeHandleForFilter()` to fail closed
     * for a disposed-but-present, feature-enabled service — matching
     * `getUnavailableResult()`.
     */
    isFeatureEnabledForFilter(): boolean;
    /**
     * Forwards a native rule-fetch telemetry record as a
     * `content_exclusion_rules_fetched` event. Used both by this shim's fetch
     * and by the streaming line filter, which drives the native orchestrator
     * directly and may trigger a cache refresh.
     */
    emitRuntimeFetchTelemetry(telemetry: {
        ruleCount: number;
        repoCount: number;
        submoduleCount: number;
        fetchDurationMs: number;
    }): void;
    /** Replays native leveled log lines through the JS logger. */
    private replayLogs;
}

