/**
 * Immutable snapshot of the repository's diff state at a point in time.
 *
 * Eagerly computes git diff data and per-file range hashes during `create()`.
 * All public methods are synchronous.
 *
 */
declare class RepoChangeSet {
    private readonly files;
    /**
     * Total attempts for the change-detection git commands (1 initial try plus retries).
     * The reads are idempotent, so re-running the whole stage+diff pass on a transient
     * failure is safe.
     */
    private static readonly GIT_COLLECT_ATTEMPTS;
    /**
     * Base backoff between change-detection retries, in milliseconds. The delay grows
     * linearly with the attempt number to give a transient condition (e.g. a Windows
     * file-handle/index lock) time to clear.
     */
    private static readonly GIT_COLLECT_RETRY_BASE_DELAY_MS;
    private constructor();
    /**
     * Creates a fully-initialized RepoChangeSet.
     * Stages all changes, retrieves changed paths (including deletions) and diff ranges,
     * then hashes each changed file's contents.
     *
     * Uses `getChangedPaths()` as the authoritative file list so that deleted files
     * and pure-deletion edits are included. `getDiffRanges()` provides hunk-level
     * line ranges where available (it intentionally omits deleted files and
     * deletion-only hunks).
     */
    static create(git: GitHandler, repoLocation: string, baseCommit: string, abortSignal?: AbortSignal): Promise<RepoChangeSet>;
    /**
     * Stages changes and collects the changed paths + diff ranges, retrying on
     * transient git failures.
     *
     * The change-detection git commands (`git add`, then two concurrent
     * `git diff` reads) can fail transiently under load — most often on Windows
     * CI, where file-handle/index-lock contention or a process-spawn hiccup
     * surfaces as a non-zero git exit. A single such hiccup previously failed
     * the entire code review / parallel validation. Retrying the (idempotent)
     * pass a couple of times absorbs the transient failure.
     *
     * Abort/timeout-like errors (e.g. the budget's SIGPIPE/SIGTERM cascade, or
     * an already-aborted signal) are never retried, so an exhausted budget or a
     * cancelled review still fails promptly instead of being prolonged.
     */
    private static collectChangesWithRetry;
    /**
     * Stages all changes and retrieves changed paths + diff ranges in a single pass.
     * Throws the underlying error, or an `AggregateError` when both reads fail.
     */
    private static collectChanges;
    /** Full diff with hunk line ranges (needed for CodeQL diff-informed analysis and alert filtering). */
    getFileRanges(): FileRange[];
    /** Set of changed file paths. */
    getChangedFiles(): Set<string>;
    /**
     * Returns the set of files that changed between a previous change set and this one.
     * Includes files that are new, modified (different hash), or deleted (in previous but not in current).
     */
    getChangedFilesSince(previous: RepoChangeSet): Set<string>;
}

