    private readonly host;
    private readonly entries;
    private readonly unsubscribeShutdown;
    private readonly unsubscribeIdle;
    private readonly unsubscribeUserMessage;
    private nextId;
    private disposed;
    /**
     * Source of the most recently started turn, captured from `user.message`
     * (which fires when a queued prompt is dequeued and run, not when enqueued).
     * An aborted `session.idle` reports only that *some* turn was cancelled, not
     * which one, so this lets {@link rearmAbortedSelfPaced} attribute the abort to
     * the turn that was actually running and re-arm only that entry.
     */
