declare type SessionScheduleApi = SessionApi["schedule"] & {
    /**
     * Install (or clear) the CLI-side fallback resolver invoked by the
     * schedule registry's tick path for slash commands that live in the CLI
     * layer (e.g. `/pr`) and so aren't in `getRuntimeSlashCommand`.
     *
     * **In-process structural extra** — only present on local (in-process)
     * sessions, where the schedule namespace is the runtime `Session`'s own
     * object. Remote facades omit it because a resolver closure can't cross
     * the JSON-RPC boundary, so callers must guard on `client.isRemote`
     * before invoking and use optional chaining.
     */
    setCommandResolver?(resolver: ScheduledCommandResolver | undefined): void;
    /**
     * Register a self-paced ("dynamic") schedule directly, bypassing the
     * natural-language cadence parse the `/every` runtime command runs. The
     * first run fires immediately and the model paces subsequent runs via the
     * `manage_schedule` `wakeup` action (see {@link wrapSelfPacedPrompt}).
     *
     * Used by CLI features that already KNOW they want a self-paced loop and
     * supply a fully-formed task prompt (e.g. `/pr auto`), so routing the prompt
     * through the schedule parser — which runs the main model and could misread
     * cadence-like text inside the prompt as a fixed interval — is both wasteful
     * and unsafe.
     *
     * **In-process structural extra** — like {@link setCommandResolver}, only
     * present on local sessions. The registry it drives lives in-process, so
     * remote facades omit it; callers must guard with optional chaining and
     * provide their own fallback for remote/relay sessions.
     */
    addSelfPaced?(prompt: string, options?: {
        displayPrompt?: string;
    }): {
        entry: ScheduleEntry;
    } | {
        error: string;
    };
};

